definition.script:
pipeline {
    agent { label 'local-security-agent' }
    options {
        buildDiscarder(logRotator(numToKeepStr: '20'))
        timeout(time: 60, unit: 'MINUTES')
    }
    environment {
        REGISTRY = '132.186.17.22:5000'
        SCAN_SEVERITY = 'CRITICAL,HIGH'
    }
    stages {
        stage('Setup') {
            steps {
                sh 'mkdir -p security-reports'
                sh 'echo "=== Tools ===" && java -version 2>&1 | head -1 && trivy --version 2>&1 | head -1 && podman --version 2>&1'
            }
        }
        stage('Secret Detection') {
            when { expression { params.SCAN_TYPE in ['full', 'code-only'] } }
            steps {
                sh 'trivy fs --scanners secret --format json --output security-reports/secret-scan.json . || true'
                sh 'trivy fs --scanners secret --format table . || true'
            }
        }
        stage('SAST Scan') {
            when { expression { params.SCAN_TYPE in ['full', 'code-only'] } }
            steps {
                sh 'trivy fs --scanners vuln,misconfig --severity CRITICAL,HIGH --format json --output security-reports/trivy-fs.json . || true'
                sh 'trivy fs --scanners vuln,misconfig --severity CRITICAL,HIGH --format table . || true'
            }
        }
        stage('Image Scan') {
            when { expression { params.SCAN_TYPE in ['full', 'image-only'] } }
            steps {
                script {
                    def img = "132.186.17.22:5000/${params.IMAGE_NAME}:${params.IMAGE_TAG}"
                    sh "trivy image --podman-host '' --severity CRITICAL,HIGH --format json --output security-reports/trivy-image.json '${img}' || true"
                    sh "trivy image --podman-host '' --severity CRITICAL,HIGH --format table '${img}' || true"
                }
            }
        }
        stage('K8s Manifest Scan') {
            when { expression { params.SCAN_TYPE in ['full', 'k8s-manifests'] } }
            steps {
                sh 'trivy config --severity CRITICAL,HIGH --format json --output security-reports/trivy-k8s.json /root/Downloads/cat-deployments || true'
                sh 'trivy config --severity CRITICAL,HIGH --format table /root/Downloads/cat-deployments || true'
            }
        }
        stage('Registry Scan') {
            when { expression { return params.SCAN_REGISTRY_IMAGES } }
            steps {
                sh 'bash /root/Downloads/cat-deployments/jenkins/security-pipeline/scripts/scan-all-images.sh || true'
            }
        }
        stage('Security Gate') {
            steps {
                script {
                    echo '=== Security Gate ==='
                    def rc = sh(script: '''
                        CRIT=0
                        if [ -f "security-reports/trivy-image.json" ]; then
                            CRIT=$(python3 -c "import json; d=json.load(open('security-reports/trivy-image.json')); print(sum(1 for r in d.get('Results',[]) for v in r.get('Vulnerabilities',[]) if v.get('Severity')=='CRITICAL'))" 2>/dev/null || echo 0)
                        fi
                        echo "CRITICAL: $CRIT"
                        [ "$CRIT" -gt 0 ] && exit 1 || exit 0
                    ''', returnStatus: true)
                    if (rc != 0 && params.FAIL_ON_CRITICAL) {
                        unstable('CRITICAL vulnerabilities detected')
                    }
                }
            }
        }
    }
    post {
        always {
            archiveArtifacts artifacts: 'security-reports/**', allowEmptyArchive: true
            echo 'Security scan complete.'
        }
    }
}
